// // This module is designed to take a 5-bit input serially and output the same 5 bits in reverse order after a delay of 5 clock cycles.
module siso_shift_register (
    input wire clk,
    input wire rst,
    input wire si,
    output reg so
);
    reg [4:0] shift_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            shift_reg <= 5'b0;
            so <= 1'b0;
        end else begin
            shift_reg <= {shift_reg[3:0], si}; // Shift left and insert SI
            so <= shift_reg[4]; // Output the MSB
        end
    end
endmodule
